// Gugustus - AntiFireball.java (full detection + attack):
@EventTarget
public void onPacketReceive(EventReceivePacket event) {
    if (event.getPacket() instanceof S0EPacketSpawnObject) {
        S0EPacketSpawnObject s0e = (S0EPacketSpawnObject) event.getPacket();
        int type = s0e.func_148993_l();
        // Type 63 = fireball (Ghast), type 64 = small fireball (Blaze, player)
        if (type == 63 || type == 64) {
            // Track this fireball for attack
            int entityId = s0e.func_149001_c();
            if (mc.theWorld != null) {
                Entity fireball = mc.theWorld.getEntityByID(entityId);
                if (fireball != null) {
                    // Send attack to deflect the fireball back
                    mc.thePlayer.sendQueue.addToSendQueue(
                        new C02PacketUseEntity(fireball, C02PacketUseEntity.Action.ATTACK));
                    mc.thePlayer.swingItem();
                }
            }
        }
    }
}

